interface class IBottom;
   pure virtual function bit foo();
endclass

interface class IMid;
   pure virtual function string bar();
endclass

class bottom implements IBottom;
   int a;
   string b;

   function new(int a, string b = "b!");
      this.a = a;
      this.b = b;
   endfunction

   virtual function bit foo();
      $display("%d", a);
   endfunction
endclass

class middle extends bottom implements IMid;
   function new(int a);
       super.new(a, "mid");
   endfunction

   virtual function bit foo();
      $display("%s", b);
   endfunction

   virtual function string bar();
     return "123";
   endfunction
endclass

class top extends middle;
   function new();
      super.new(-39);
   endfunction
endclass

module t;/*AUTOARG*/
   // Inputs

   initial begin
      bottom bot = new(42);
      middle mid = new(-1);

      `checks( bot.b, "b!" );
      `checks( mid.a, -1 );
      $finish;
   end

endmodule
