This doesn't even compile. The constructor parameters C++ mapping is broken (at least) for virtual class inheritance - on the top-most level (the deepest child), super.new(params) are not passed to all the bases, which is incorrect. I have this quick ugly hack, but we need to address it systematically and if possible add the cases to the SV testsuite. 

Default new() parameter passing is another thing. Is there i reason why we substitute in-place rather than mapping SV default arguments to C++ default arguments? What if i call a function in the argument default assignment (is this even legal in SV? but it works e.g. with Dsim).

The quick ugly hack: it actually works in my _real-world_ case, but it anyways fail to compile the test case posted above.

`src/V3EmitCFunc.h`:
```c++
    const AstCNew* getClassConstructorSuperNewCall(AstClass* classp) {
        AstCFunc* constructorFunc = nullptr;
        classp->foreachMember([&](AstClass* /*unused*/, AstCFunc* cfuncp) {
            if (cfuncp->isConstructor()) {
                constructorFunc = cfuncp;
            }
        });
        if (!constructorFunc) return nullptr;
        return getSuperNewCallRecursep(constructorFunc->stmtsp());
    }
    void putConstructorSubinit(const AstClass* classp, AstCFunc* cfuncp, bool top,
                            std::set<AstClass*>& doneClassesr) {
        for (const AstClassExtends* extp = classp->extendsp(); extp;
            extp = VN_AS(extp->nextp(), ClassExtends)) {
            if (extp->classp()->useVirtualPublic()) {
                // It's a c++ virtual class (diamond relation)  
                // Must get the subclasses initialized first
                putConstructorSubinit(extp->classp(), cfuncp, false, doneClassesr);
            }
            // Diamond pattern with same base class twice?
            if (doneClassesr.find(extp->classp()) != doneClassesr.end()) continue;
            puts(doneClassesr.empty() ? "" : "\n    , ");
            doneClassesr.emplace(extp->classp());
            puts(prefixNameProtect(extp->classp()));
            if (constructorNeedsProcess(extp->classp())) {
                puts("(vlProcess, vlSymsp");
            } else {
                puts("(vlSymsp");
            }
            const AstCNew* superNewCallp = nullptr;
            if (top) {
                superNewCallp = getSuperNewCallRecursep(cfuncp->stmtsp());
            } else if (extp->classp()->useVirtualPublic() && !extp->classp()->isInterfaceClass()) {
                superNewCallp = getClassConstructorSuperNewCall(const_cast<AstClass*>(classp));
            }

            if (superNewCallp) {
                putCommaIterateNext(superNewCallp->argsp(), true);
            }
            puts(")");
            top = false;
        }
    }
